// Extract messaging event from Meta webhook payload
const body = $input.first().json.body;
const entry = body?.entry?.[0];
const messaging = entry?.messaging?.[0];

if (!messaging) return [{ json: { skip: true, reason: 'no_messaging_event' } }];
if (messaging.delivery || messaging.read) return [{ json: { skip: true, reason: 'delivery_or_read_event' } }];
if (messaging.message?.is_echo) return [{ json: { skip: true, reason: 'echo_message' } }];
if (!messaging.message?.text) return [{ json: { skip: true, reason: 'no_text_message' } }];

return [{ json: { skip: false, senderPsid: messaging.sender.id, messageText: messaging.message.text, timestamp: messaging.timestamp } }];

// HYBRID ROUTER v3: Language detection + Rules-first routing
// Fixes: consistent replyText output, language style detection, BD-friendly

const msg = $input.first().json.messageText;
const psid = $input.first().json.senderPsid;
const normalized = msg.toLowerCase().trim().replace(/[^a-z0-9\s\u0980-\u09FF]/g, '');
const words = normalized.split(/\s+/);

// --- LANGUAGE DETECTION ---
const banglaRegex = /[\u0980-\u09FF]/;
const banglishWords = ['ki','kemon','ache','chai','korbo','hobe','diben','koto','dam','poro','eid','salam','bhai','apa','vai','dada','onek','sundor','valo','kobe','dhorte','pathaben'];
let languageStyle = 'english';
if (banglaRegex.test(msg)) {
  languageStyle = 'bangla';
} else if (words.some(w => banglishWords.includes(w)) || /\b(er|ta|tay|te|gulo)\b/.test(normalized)) {
  languageStyle = 'banglish';
}

// --- BRANCH 1: Static Greetings (NO AI) ---
const greetings = ['hi','hello','hey','hola','assalamualaikum','salam','yo','sup','walaikum'];
const thanks = ['thanks','thank','thankyou','thx','jazakallah','shukria','dhonnobad'];
const byes = ['bye','goodbye','later','seeya','cya','allah hafez','khuda hafez'];

if (words.length <= 4) {
  if (words.some(w => greetings.includes(w))) {
    const replies = {
      bangla: 'ওয়ালাইকুমুস সালাম! আমাদের স্টোরে স্বাগতম। আমি আপনাকে প্রোডাক্ট খুঁজতে, প্রশ্নের উত্তর দিতে বা অর্ডার করতে সাহায্য করতে পারি। কী খুঁজছেন?',
      banglish: 'Walaikumussalam! Amader store e welcome. Ami apnake product khujte, question er answer dite ba order korte help korte pari. Ki khujchen?',
      english: 'Hello! Welcome to our store. I can help you find products, answer questions, or place an order. What are you looking for today?'
    };
    return [{ json: { route: 'greeting', senderPsid: psid, customerMessage: msg, intent: 'greeting', replyText: replies[languageStyle], needsHumanSupport: false, languageStyle } }];
  }
  if (words.some(w => thanks.includes(w))) {
    const replies = { bangla: 'আপনাকে স্বাগতম! আর কিছু লাগলে জানাবেন।', banglish: 'Apnake welcome! Ar kichu lagle janaben.', english: 'You are welcome! Let me know if there is anything else I can help with.' };
    return [{ json: { route: 'thanks', senderPsid: psid, customerMessage: msg, intent: 'thanks', replyText: replies[languageStyle], needsHumanSupport: false, languageStyle } }];
  }
  if (words.some(w => byes.includes(w))) {
    const replies = { bangla: 'আল্লাহ হাফেজ! আবার আসবেন। ধন্যবাদ!', banglish: 'Allah hafez! Abar asben. Dhonnobad!', english: 'Goodbye! Thanks for chatting. Come back anytime!' };
    return [{ json: { route: 'bye', senderPsid: psid, customerMessage: msg, intent: 'bye', replyText: replies[languageStyle], needsHumanSupport: false, languageStyle } }];
  }
}

// --- BRANCH 6: Human Support (NO AI) ---
const supportWords = ['human','agent','person','representative','manager','speak to','talk to','complaint','refund','fraud','overcharged','legal','lawyer','wrong item','damaged','broken','manush','kotha bolte chai','somossa'];
const angryPatterns = (msg === msg.toUpperCase() && msg.length > 10) || msg.includes('!!!');
if (supportWords.some(w => normalized.includes(w)) || angryPatterns) {
  const replies = { bangla: 'আমি বুঝতে পারছি আপনার সাহায্য দরকার। আমাদের টিম ২-৪ ঘণ্টার মধ্যে আপনার সাথে যোগাযোগ করবে। জরুরি হলে support@yourbrand.com এ ইমেইল করুন।', banglish: 'Ami bujhte parchi apnar help dorkar. Amader team 2-4 ghontar moddhe apnar sathe jogajog korbe. Joruri hole support@yourbrand.com e email korun.', english: 'I understand you need help from our team. They will respond within 2-4 hours (Mon-Fri, 9AM-6PM). If urgent, email support@yourbrand.com.' };
  return [{ json: { route: 'support', senderPsid: psid, customerMessage: msg, intent: 'human_support', replyText: replies[languageStyle], needsHumanSupport: true, languageStyle, telegramAlertText: `SUPPORT REQUEST\nPSID: ${psid}\nMessage: ${msg}\nLanguage: ${languageStyle}\nReason: customer_requested` } }];
}

// --- BRANCH 5: Order Tracking (NO AI) ---
const trackWords = ['track','tracking','where is my order','order status','delivery status','has it shipped','my order','when will it arrive','order kothay','delivery kobe','parcel'];
const orderIdMatch = msg.match(/ORD-[\w-]+/i);
if (trackWords.some(w => normalized.includes(w)) || orderIdMatch) {
  let reply;
  if (orderIdMatch) {
    reply = languageStyle === 'bangla' ? `আপনার অর্ডার ${orderIdMatch[0].toUpperCase()} খুঁজে দেখছি। আমাদের টিম শীঘ্রই আপডেট দিবে।` : languageStyle === 'banglish' ? `Apnar order ${orderIdMatch[0].toUpperCase()} khuje dekhchi. Amader team sighri update dibe.` : `I found your order reference: ${orderIdMatch[0].toUpperCase()}. Our team will update you shortly.`;
  } else {
    reply = languageStyle === 'bangla' ? 'আপনার অর্ডার নম্বরটি দিন (ORD-YYYYMMDD-XXX)।' : languageStyle === 'banglish' ? 'Apnar order number ta din (ORD-YYYYMMDD-XXX).' : 'Please provide your order number (format: ORD-YYYYMMDD-XXX).';
  }
  return [{ json: { route: 'tracking', senderPsid: psid, customerMessage: msg, intent: 'order_tracking', replyText: reply, needsHumanSupport: false, languageStyle } }];
}

// --- BRANCH 4: Order Intent (NO AI) ---
const buyWords = ['buy','order','purchase','i want','ill take','add to cart','i need','id like','kinbo','order korbo','nibo','chai','kinte','buy korte'];
if (buyWords.some(w => normalized.includes(w))) {
  const replies = { bangla: 'অর্ডার করতে চাইলে জানান:\n1. কোন প্রোডাক্ট?\n2. সাইজ?\n3. কালার?\n4. নাম ও নম্বর\n5. ঠিকানা\n\nকোন প্রোডাক্ট পছন্দ হয়েছে?', banglish: 'Order korte chaile janan:\n1. Kon product?\n2. Size?\n3. Color?\n4. Naam o number\n5. Address\n\nKon product pochondo hoyeche?', english: 'To place an order, I need:\n1. Which product?\n2. Size?\n3. Color?\n4. Name & phone\n5. Address\n\nWhich product are you interested in?' };
  return [{ json: { route: 'order_intent', senderPsid: psid, customerMessage: msg, intent: 'order_create', replyText: replies[languageStyle], needsHumanSupport: false, languageStyle } }];
}

// --- Pass to FAQ/Product/AI check ---
return [{ json: { route: 'check_sheets', senderPsid: psid, customerMessage: msg, normalized, languageStyle, intent: 'unknown_yet', needsHumanSupport: false } }];

// FAQ + PRODUCT SEARCH (NO AI COST) - v3 Fixed
// Outputs consistent: senderPsid, customerMessage, intent, replyText, needsHumanSupport, languageStyle

try {
  const routerData = $('Needs Sheet Lookup?').first().json;
  const customerMsg = routerData.customerMessage;
  const normalized = routerData.normalized;
  const psid = routerData.senderPsid;
  const languageStyle = routerData.languageStyle || 'english';
  const words = normalized.split(/\s+/).filter(w => w.length > 2).filter(w => !['the','and','for','are','this','that','with','have','show','want','your','what','does','come','any','can','you','please','hello','much','how','there','ami','apni','kono','holo','kore','theke'].includes(w));

  // --- TRY FAQ ---
  const faqRows = $('Read FAQ Sheet').all().map(i => i.json);
  const activeFaqs = faqRows.filter(f => String(f.Active).toUpperCase() === 'YES');
  let bestFaq = null; let bestFaqScore = 0;
  for (const faq of activeFaqs) {
    const faqKeywords = (faq.Keywords || '').toLowerCase().split(',').map(k => k.trim());
    const questionWords = (faq.Question || '').toLowerCase().split(/\s+/);
    let score = 0;
    for (const word of words) {
      if (faqKeywords.some(k => k.includes(word) || word.includes(k))) score += 2;
      if (questionWords.includes(word)) score += 1;
    }
    if (score > bestFaqScore) { bestFaqScore = score; bestFaq = faq; }
  }
  if (bestFaq && bestFaqScore >= 3) {
    return [{ json: { route: 'faq_match', senderPsid: psid, customerMessage: customerMsg, intent: 'faq', replyText: bestFaq.Answer, needsHumanSupport: false, languageStyle, aiUsed: false } }];
  }

  // --- TRY PRODUCTS ---
  const productRows = $('Read Products Sheet').all().map(i => i.json);
  const activeProducts = productRows.filter(p => String(p.Active).toUpperCase() === 'YES');
  const scored = activeProducts.map(product => {
    const searchable = [product.Product_Name||'', product.Category||'', product.Description||'', product.Size||'', product.Color||'', product.Search_Keywords||''].join(' ').toLowerCase();
    let score = 0;
    for (const term of words) { if (searchable.includes(term)) score++; }
    return { ...product, score };
  }).filter(p => p.score > 0);

  const grouped = {};
  for (const m of scored) {
    const pid = m.Product_ID;
    if (!grouped[pid]) { grouped[pid] = { Product_ID: pid, Product_Name: m.Product_Name, Price: m.Price, Currency: m.Currency||'BDT', sizes: [], colors: [], inStock: 0, topScore: 0 }; }
    if (m.score > grouped[pid].topScore) grouped[pid].topScore = m.score;
    if (String(m.In_Stock).toUpperCase() === 'YES') {
      grouped[pid].inStock++;
      if (m.Size && !grouped[pid].sizes.includes(m.Size)) grouped[pid].sizes.push(m.Size);
      if (m.Color && !grouped[pid].colors.includes(m.Color)) grouped[pid].colors.push(m.Color);
    }
  }
  const results = Object.values(grouped).sort((a,b) => b.topScore - a.topScore).slice(0, 5);

  if (results.length > 0) {
    let reply = '';
    if (languageStyle === 'bangla') { reply = `${results.length}টি প্রোডাক্ট পেয়েছি:\n\n`; }
    else if (languageStyle === 'banglish') { reply = `${results.length}ta product peyechi:\n\n`; }
    else { reply = `I found ${results.length} product${results.length>1?'s':''}:\n\n`; }
    results.forEach((p, i) => {
      reply += `${i+1}. ${p.Product_Name} — ৳${p.Price}\n`;
      if (p.sizes.length) reply += `   Size: ${p.sizes.join(', ')}\n`;
      if (p.colors.length) reply += `   Color: ${p.colors.join(', ')}\n`;
      if (p.inStock === 0) reply += `   (Out of stock)\n`;
      reply += '\n';
    });
    if (languageStyle === 'bangla') reply += 'কোনটা অর্ডার করতে চান? সাইজ ও কালার জানান!';
    else if (languageStyle === 'banglish') reply += 'Konta order korte chan? Size o color janan!';
    else reply += 'Want to order? Tell me the product, size, and color!';
    return [{ json: { route: 'product_match', senderPsid: psid, customerMessage: customerMsg, intent: 'product_inquiry', replyText: reply, needsHumanSupport: false, languageStyle, aiUsed: false } }];
  }

  // --- NO MATCH: Build context for AI ---
  const productSummary = [...new Set(activeProducts.map(p => p.Category))].slice(0,6).join(', ');
  if (words.length === 0) {
    const fallback = languageStyle === 'bangla' ? 'আমি সাহায্য করতে চাই! প্রোডাক্ট, শিপিং, রিটার্ন, সাইজ নিয়ে জিজ্ঞেস করতে পারেন।' : languageStyle === 'banglish' ? 'Ami help korte chai! Product, shipping, return, size niye jiggesh korte paren.' : "I'd love to help! Ask about products, shipping, returns, or sizing.";
    return [{ json: { route: 'ai_fallback', senderPsid: psid, customerMessage: customerMsg, intent: 'unclear', replyText: fallback, needsHumanSupport: false, languageStyle, aiUsed: false } }];
  }

  return [{ json: { route: 'ai_fallback', senderPsid: psid, customerMessage: customerMsg, intent: 'complex_question', replyText: '', needsHumanSupport: false, languageStyle, aiUsed: true, availableCategories: productSummary } }];
} catch (err) {
  const psid = $input.first()?.json?.senderPsid || '';
  const msg = $input.first()?.json?.customerMessage || '';
  return [{ json: { route: 'error', senderPsid: psid, customerMessage: msg, intent: 'error', replyText: 'Sorry, something went wrong. Please try again or type "human" for support.', needsHumanSupport: true, languageStyle: 'english', aiUsed: false, telegramAlertText: `ERROR in FAQ/Product search\nPSID: ${psid}\nError: ${err.message}` } }];
}

// PREPARE REPLY v3 - Fixed to handle AI Agent output correctly
// The AI Agent node outputs in .output field (LangChain format)
try {
  const data = $input.first().json;
  let psid = data.senderPsid || '';
  let replyText = '';

  // Priority order for finding reply text:
  // 1. Direct replyText from rule-based branches
  if (data.replyText && data.replyText.length > 0) {
    replyText = data.replyText;
  }
  // 2. AI Agent output (LangChain agent outputs in .output)
  else if (data.output && typeof data.output === 'string' && data.output.length > 0) {
    replyText = data.output;
  }
  // 3. AI Agent text field
  else if (data.text && typeof data.text === 'string' && data.text.length > 0) {
    replyText = data.text;
  }
  // 4. Response field
  else if (data.response && typeof data.response === 'string') {
    replyText = data.response;
  }
  // 5. Fallback
  else {
    replyText = 'I apologize for the inconvenience. Please type "human" and our team will assist you directly.';
  }

  // Truncate for Messenger 2000 char limit
  if (replyText.length > 1950) {
    replyText = replyText.substring(0, 1947) + '...';
  }

  // Get PSID from various possible locations
  if (!psid && data.senderPsid) psid = data.senderPsid;

  return [{ json: { senderPsid: psid, replyText: replyText, needsHumanSupport: data.needsHumanSupport || false, telegramAlertText: data.telegramAlertText || '' } }];
} catch (err) {
  return [{ json: { senderPsid: '', replyText: 'Something went wrong. Type "human" for support.', needsHumanSupport: true, telegramAlertText: 'ERROR in Prepare Reply: ' + err.message } }];
}

// TRACKING LOOKUP (NO AI COST)
// Search Tracking tab by Order_ID or customer email
const data = $input.first().json;
const psid = data.senderPsid;
const orderId = data.orderId;
const msg = data.messageText;

// For v2, reply with instructions since we don't have tracking data connected yet
let reply = '';
if (orderId) {
  reply = `I found your order reference: ${orderId}\n\nLet me check the status for you. Our team will update you shortly with tracking details.\n\nIf you need immediate help, type "speak to a human".`;
} else {
  reply = 'I can help you track your order! Please provide your order number (it looks like ORD-YYYYMMDD-XXX).\n\nExample: "Track ORD-20250120-001"';
}

return [{ json: { route: 'tracking', senderPsid: psid, replyText: reply, aiUsed: false } }];

// SUPPORT TICKET HANDLER (NO AI COST)
const data = $input.first().json;
const psid = data.senderPsid;
const msg = data.messageText || '';

const reply = `I understand you need help from our team. I have flagged your conversation for priority support.\n\nOur team will respond to you in this chat within 2-4 hours (business hours: Mon-Fri, 9 AM - 6 PM).\n\nIf urgent, you can also email: support@yourbrand.com\n\nIs there anything else I can help with while you wait?`;

return [{ json: { route: 'support', senderPsid: psid, replyText: reply, aiUsed: false } }];

// ORDER INTENT HANDLER
const data = $input.first().json;
const psid = data.senderPsid;
const msg = data.messageText || '';

const reply = `Great, I would love to help you place an order!

To create your order, I need:
1. Which product? (e.g., Classic Black T-Shirt)
2. What size?
3. What color?
4. Your name and email
5. Shipping address

Which product are you interested in? You can also say "show me t-shirts" to browse first.`;

return [{ json: { route: 'order_intent', senderPsid: psid, replyText: reply, aiUsed: false } }];

// Send Telegram alert for human support cases
const data = $input.first().json;
const alertText = data.telegramAlertText || '';
const psid = data.senderPsid || 'unknown';
const needsAlert = data.needsHumanSupport === true && alertText.length > 0;

if (!needsAlert) {
  // No alert needed, pass through
  return [{ json: data }];
}

// Format the Telegram message
const timestamp = new Date().toISOString().replace('T',' ').substring(0,19);
const telegramMessage = `🚨 HUMAN SUPPORT NEEDED\n\n${alertText}\n\nTime: ${timestamp}`;

return [{ json: { ...data, telegramMessage, sendAlert: true } }];
